/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    $c.gus.cfDisableObjects(grp_save);
    $c.gus.cfDisableBtn([btn_update, btn_save]);
    gr_slipKnd.setNoResultMessageVisible(false);
    ds_slipKind.reform();
    ds_slipKind.removeAll();
    totalRows.setValue("0");
    c_slipKndCd.focus();
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
};

/**
 * 조회
 */
scwin.f_Retrieve = function() {
    // ds_search.UseChangeInfo = false
    // sbm_search.setAction = "/ac.fi.stdinfomgnt.RetrieveSlipKindListCMD.do";
    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_slipKnd.setNoResultMessageVisible(true);
    let rowCnt = ds_slipKind.getRowCount();
    totalRows.setValue(rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다

        } else {
            //조회된 결과 정렬(asis:<param name=SortExpr 참조)
            ds_slipKind.sort("slipKndCd", 0);
            gr_slipKnd.setFocusedCell(0, 0);
            $c.gus.cfDisableBtn([btn_save]);
        }
    }
};

/**
 * 행추가
 */
scwin.f_AddItem = async function() {
    if(ds_slipKind.getInsertedIndex().length > 0) {
        let ret = await scwin.f_Validation();
        if(!ret) {
            return false;
        }
    }
    let row = ds_slipKind.insertRow();
    gr_slipKnd.setFocusedCell(row, 0, false);
    lc_useYn.setValue(1);
    // $c.gus.cfEnableKeyData();
    $c.gus.cfEnableObjects(grp_save);
    $c.gus.cfDisableBtn([btn_update]);
    ed_slipKndCd.focus();
};

/**
 * 수정버튼
 */
scwin.f_Update = function() {
    // disable 처리
    $c.gus.cfEnableObjects(grp_save);
    $c.gus.cfEnableObjects([ed_slipKndNm]);
    $c.gus.cfDisableObjects([ed_slipKndCd]);
    $c.gus.cfDisableBtn([btn_update]);
    //focus 설정
    // ed_slipKndNm.focus();
};

/**
 * 취소
 */
scwin.f_Cancel = function(e) {
    $c.data.undoRow(ds_slipKind, "N");
    $c.gus.cfDisableObjects(grp_save);
    $c.gus.cfDisableBtn([btn_save]);
};

