/**
 * 저장 시 입력 Validation
 */
scwin.f_Validation = async function () {
    //Mandatory 항목이 누락하지 않았는지 체크한다.
    // if (!cfCheckMandatory())
    // return false;

    // 체크(전표종류코드, 전표종류명)
    let ret = await $c.gus.cfValidate([ed_slipKndCd, ed_slipKndNm]);
    if(!ret) {
        return false;
    }
    return true;
};

/**
 * scwin.f_ValidationSync 사용하기 위한 함수
 */
scwin.myCfValidate = function (oElement) {
    let obj = $c.gus.object(oElement);
    if (obj.length != null) {
		for (var i = 0; i < obj.length; i++) {
            let id = obj[i];
            if($c.gus.cfIsNull(id.getValue())) {
                $c.win.alert(id.options.title + "은(는) 필수 입력 항목입니다.");
                id.focus();
                return false;
            }
        }
    }
    return true;
};

/**
 * onbeforerowpositionchange 사용을 위한 validation 체크
 */
scwin.f_ValidationSync = function() {
    //필수값 임의로 체크(전표종류코드, 전표종류명)
    let ret = scwin.myCfValidate([ed_slipKndCd, ed_slipKndNm]);
    if(!ret) {
        return false;
    }
    return true;
};


/**
 * 저장버튼
 */
scwin.f_Save = async function () {
    //변경한 데이터가 있는지 체크한다.
    // if (ds_slipKind.IsUpdated == false) {
    if (ds_slipKind.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["데이타"]);
        return;
    }

    // 체크
    if (!await scwin.f_Validation()) {
        return;
    }

    let ret = await $c.gus.cfValidate([gr_slipKnd])
    if (!ret) {
        return false;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        ds_slipKind.reform();
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve(); 
    }
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 팝업호출
