    //asis 소스
    // 전표종류
    // rtnList = cfCommonPopUp('retrieveSlipKndCd', c_slipKndCd.text.trim(), c_slipKndNm.value, check, null, null, null, null, null, null, null, null, null);
    // scwin.f_resultPopEd(c_slipKndCd, c_slipKndNm, rtnList);
    udc_c_slipKndCd.cfCommonPopUp(scwin.udc_c_slipKndCd_callBackFunc, c_slipKndCd.getValue(), c_slipKndNm.getValue(), check, null
                            , null, null, null, null, null
                            , null, null, null, null, null
                            , null, null
    );
};
/**
 * 전표종류(조회용) 팝업 callBack
 */
scwin.udc_c_slipKndCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        c_slipKndCd.setValue(ret[0]);        // 전표종류코드
        c_slipKndNm.setValue(ret[1]);        // 전표종류명
        c_slipKndCd.hidVal = ret[0];         // 히든값
    } else {
        c_slipKndCd.setValue("");            // 전표종류코드
        c_slipKndNm.setValue("");            // 전표종류명
        c_slipKndCd.hidVal = "";             // 히든값
    }
};


