/**
 * 그리드 값 변경(decode 대신 처리)
 */
scwin.decodeYnExp = function (data) {
    return $c.gus.decode(data, "1", "사용", "0", "미사용", "");
};
scwin.decodeYnExp2 = function (data) {
    return $c.gus.decode(data, "1", "Y", "0", "N", "");
};

/**
 * 전표종류코드용(대문자1+숫자2)
 */
scwin.removeKor = function (id) {
    var v = id.getValue().toUpperCase();
    //한글방지
    v = v.replace(/[ㄱ-ㅎㅏ-ㅣ가-힣]/g, "");
    //영문 대문자 + 숫자만 남기기
    v = v.replace(/[^A-Z0-9]/g, "");

    // 길이 제한
    if (v.length > 3) v = v.substring(0, 3);

    // 패턴 보정
    if (v.length >= 1 && !/[A-Z]/.test(v.charAt(0))) {
        v = "";
    }
    if (v.length >= 2 && !/[0-9]/.test(v.charAt(1))) {
        v = v.substring(0, 1);
    }
    if (v.length >= 3 && !/[0-9]/.test(v.charAt(2))) {
        v = v.substring(0, 2);
    }
    id.setValue(v);
};

/**
 * 전표종류코드
 */
scwin.ed_slipKndCd_onkeyup = function (e) {
    scwin.removeKor(ed_slipKndCd);
};



