/**
 * 전표종류(조회영역) 팝업 호출
 */
scwin.udc_c_slipKndCd_onclickEvent = function (e) {
    // if(c_slipKndCd.hidVal != c_slipKndCd.getValue()) {
    //     c_slipKndNm.setValue("");
    // }
    let close = "F";
    if(!$c.gus.cfIsNull(c_slipKndCd.getValue())) {
        close = "T";
    }
    let id = e.target.id;
    if(id.indexOf("btn") > -1) {
        close = "F";
    }
    scwin.f_openPopUp("1", close);
};
scwin.udc_c_slipKndCd_onblurCodeEvent = function (e) {
    if(c_slipKndCd.hidVal == c_slipKndCd.getValue()) {
        return;
    }
    c_slipKndNm.setValue("");
    c_slipKndCd.hidVal = "";
    if(!$c.gus.cfIsNull(c_slipKndCd.getValue())) {
        scwin.f_openPopUp("1", "T");
    }
};

