/*##############################################################
 * 그리드, 트리뷰, 데이터리스트 이벤트
 *##############################################################*/
/**
 * DataList의 rowPosition이 변경된 경우 발생
 */
scwin.ds_slipKind_onrowpositionchange = function (info) {
    if (ds_slipKind.getRowStatus(info.newRowIndex) == "C") {
        $c.gus.cfEnableKeyData();
    } else {
        //기타 데이타 -> 초기화, 수정, 삭제버튼 활성화
        $c.gus.cfDisableObjects(grp_save);
        $c.gus.cfDisableBtn([btn_save]);
    }
};

 /**
 * DataList의 rowPosition이 변경되기 직전에 발생하며 rowPosition의 변경 적용 여부를 결정
 * asis : 그리드 로우를 변경하려고 할 경우 - 필수항목 체크
 * tobe : 현재 $c.gus.cfValidate 사용 시 async라 이벤트에 async주면 return false안먹힘
 */
scwin.ds_slipKind_onbeforerowpositionchange = function (info) {
    if (ds_slipKind.getRowStatus(info.oldRowIndex) == "C"
        || ds_slipKind.getRowStatus(info.oldRowIndex) == "U") {            
        return scwin.f_ValidationSync();
    }
};
